query NelByColo(
  $zoneTag: string
  $filter: NelReportsAdaptiveGroupsFilter_InputObject
) {
  viewer {
    zones(filter: { zoneTag: $zoneTag }) {
      series: nelReportsAdaptiveGroups(limit: 10000, filter: $filter)
        @connection(key: "NelByColo", filter: ["filter"]) {
        count
        dimensions {
          lastKnownGoodColoCode
          type
        }
        avg {
          sampleInterval
        }
      }
    }
  }
}

